        long long max_len = 0;
        for (long long neighbor : adj[node]) {
            max_len = max(max_len, dfs(neighbor, new_mask, left, right));
        }

        // Check if current node's label can be added to the palindrome
        long long current_len = 0;
        if (left == right) {
            current_len = 1;
        } else if (label[node] == label[left] && label[node] == label[right]) {
            current_len = 3;
        } else if (label[node] == label[left] || label[node] == label[right]) {
            current_len = 2;
        }

        // Update memoization
        memo[mask] = max(max_len, current_len);

        return memo[mask];
    };

    long long max_palindrome = 0;
    for (long long i = 0; i < n; ++i) {
        long long mask = 1 << i;
        long long current_len = 1;
        max_palindrome = max(max_palindrome, current_len);
        for (long long neighbor : adj[i]) {
            long long new_mask = mask | (1 << neighbor);
            long long left = i;
            long long right = i;
            long long len = dfs(neighbor, new_mask, left, right);
            max_palindrome = max(max_palindrome, len);
        }
    }

    return max_palindrome;
}
